export const recipes: RecipeData[] = [
  // === ITALIAN ===
  { title: "Classic Margherita Pizza", description: "A simple Neapolitan pizza with fresh mozzarella, San Marzano tomatoes, and basil on a thin crispy crust.", cuisine: "Italian", diet: ["Vegetarian"], cookTimeMinutes: 25, servings: 4, ingredients: ["500g pizza dough", "200g San Marzano tomatoes, crushed", "250g fresh mozzarella, torn", "Fresh basil leaves", "2 tbsp extra virgin olive oil", "Sea salt to taste"], instructions: ["Preheat oven to 250°C (480°F) with a pizza stone inside.", "Stretch dough into a 12-inch round on a floured surface.", "Spread crushed tomatoes evenly, leaving a 1-inch border.", "Distribute torn mozzarella across the surface.", "Bake for 8-10 minutes until crust is golden and cheese bubbles.", "Top with fresh basil and drizzle with olive oil before serving."] },
  { title: "Risotto ai Funghi", description: "Creamy Italian rice slowly cooked with porcini mushrooms, white wine, and Parmesan cheese.", cuisine: "Italian", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 40, servings: 4, ingredients: ["320g arborio rice", "30g dried porcini mushrooms, rehydrated", "200g fresh mushrooms, sliced", "150ml dry white wine", "80g Parmesan, grated", "50g butter", "2 shallots, finely diced", "1L vegetable broth, warm"], instructions: ["Soak dried porcini in warm water for 20 minutes. Drain and reserve liquid.", "Sauté shallots in half the butter until soft. Add fresh mushrooms and cook 5 minutes.", "Add rice and toast for 2 minutes, stirring constantly.", "Pour in wine and stir until absorbed.", "Add broth one ladle at a time, stirring frequently, waiting until absorbed before adding more.", "After 18 minutes, stir in porcini and their liquid.", "Remove from heat, stir in remaining butter and Parmesan. Rest 2 minutes before serving."] },
  { title: "Caprese Salad", description: "Fresh buffalo mozzarella with ripe tomatoes, basil, and a drizzle of balsamic glaze.", cuisine: "Italian", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 10, servings: 2, ingredients: ["250g buffalo mozzarella, sliced", "3 large ripe tomatoes, sliced", "Fresh basil leaves", "2 tbsp balsamic glaze", "3 tbsp extra virgin olive oil", "Flaky sea salt", "Freshly ground black pepper"], instructions: ["Alternate slices of tomato and mozzarella on a plate.", "Tuck basil leaves between the slices.", "Drizzle with olive oil and balsamic glaze.", "Season with salt and pepper. Serve immediately."] },
  { title: "Tiramisu", description: "Layers of espresso-soaked ladyfingers and mascarpone cream dusted with cocoa powder.", cuisine: "Italian", diet: ["Vegetarian"], cookTimeMinutes: 30, servings: 8, ingredients: ["500g mascarpone cheese", "6 egg yolks", "150g sugar", "300ml strong espresso, cooled", "3 tbsp Marsala wine", "30 ladyfinger biscuits", "Unsweetened cocoa powder for dusting"], instructions: ["Whisk egg yolks and sugar until pale and thick.", "Fold in mascarpone until smooth.", "Mix cooled espresso with Marsala wine.", "Briefly dip ladyfingers in espresso mixture (don't soak).", "Layer dipped ladyfingers in a dish, spread half the mascarpone cream.", "Repeat with another layer of ladyfingers and remaining cream.", "Refrigerate for at least 4 hours. Dust with cocoa before serving."] },
  { title: "Spaghetti Carbonara", description: "Classic Roman pasta with eggs, pecorino cheese, guanciale, and black pepper — no cream allowed.", cuisine: "Italian", diet: [], cookTimeMinutes: 20, servings: 4, ingredients: ["400g spaghetti", "200g guanciale, cut into strips", "4 egg yolks + 2 whole eggs", "100g pecorino romano, finely grated", "Freshly ground black pepper"], instructions: ["Cook spaghetti in well-salted boiling water until al dente.", "Meanwhile, cook guanciale in a cold pan over medium heat until crispy.", "Whisk eggs, yolks, and pecorino together with plenty of black pepper.", "Drain pasta, reserving 1 cup pasta water.", "Toss hot pasta with guanciale (off heat), then quickly stir in egg mixture.", "Add pasta water a splash at a time until creamy. Serve immediately."] },
  { title: "Osso Buco", description: "Braised veal shanks in white wine and broth, served with gremolata and saffron risotto.", cuisine: "Italian", diet: ["Gluten-Free"], cookTimeMinutes: 150, servings: 4, ingredients: ["4 veal shanks, 3cm thick", "2 carrots, diced", "2 celery stalks, diced", "1 onion, diced", "250ml dry white wine", "400ml beef broth", "400g canned tomatoes", "Zest of 1 lemon", "2 tbsp fresh parsley, chopped", "2 garlic cloves, minced"], instructions: ["Season veal shanks with salt and pepper. Dredge in flour and sear in olive oil until golden on both sides.", "Remove shanks. Sauté carrots, celery, and onion in the same pan for 5 minutes.", "Add white wine and scrape up browned bits. Simmer until reduced by half.", "Add tomatoes and broth. Return shanks to pan.", "Cover and braise in a 160°C oven for 2 hours until meat is fork-tender.", "Make gremolata: mix lemon zest, parsley, and garlic.", "Serve shanks with sauce, topped with gremolata."] },
  { title: "Bruschetta al Pomodoro", description: "Toasted bread rubbed with garlic and topped with diced tomatoes, basil, and olive oil.", cuisine: "Italian", diet: ["Vegan", "Dairy-Free"], cookTimeMinutes: 10, servings: 4, ingredients: ["1 ciabatta loaf, sliced 2cm thick", "4 ripe tomatoes, diced", "2 garlic cloves", "Fresh basil, torn", "3 tbsp extra virgin olive oil", "1 tbsp balsamic vinegar", "Salt and pepper to taste"], instructions: ["Toast bread slices under a grill until golden on both sides.", "Rub one side of each toast with a cut garlic clove.", "Toss diced tomatoes with olive oil, balsamic, basil, salt, and pepper.", "Spoon tomato mixture onto garlic-rubbed toasts.", "Serve immediately."] },
  { title: "Panna Cotta", description: "Silky vanilla cream dessert set with gelatin, served with berry compote.", cuisine: "Italian", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 15, servings: 6, ingredients: ["500ml heavy cream", "80g sugar", "1 vanilla bean, split", "2 sheets gelatin (or 7g powdered)", "200g mixed berries", "2 tbsp sugar for compote", "1 tbsp lemon juice"], instructions: ["Soak gelatin sheets in cold water for 5 minutes.", "Heat cream, sugar, and vanilla seeds until just simmering (don't boil).", "Remove from heat, squeeze gelatin and stir in until dissolved.", "Pour into 6 ramekins. Refrigerate for 4+ hours until set.", "Simmer berries with sugar and lemon juice for 5 minutes for compote.", "Unmold panna cotta and serve with berry compote."] },
  { title: "Minestrone Soup", description: "Hearty Italian vegetable soup with beans, pasta, and seasonal vegetables in tomato broth.", cuisine: "Italian", diet: ["Vegan", "Dairy-Free"], cookTimeMinutes: 45, servings: 6, ingredients: ["2 cans cannellini beans, drained", "150g small pasta (ditalini)", "2 zucchini, diced", "2 carrots, diced", "2 celery stalks, diced", "400g canned tomatoes", "200g kale, chopped", "4 garlic cloves, minced", "1.5L vegetable broth", "2 tbsp olive oil"], instructions: ["Heat olive oil in a large pot. Sauté garlic, carrots, and celery for 5 minutes.", "Add zucchini and cook 3 more minutes.", "Pour in tomatoes and broth. Bring to a boil.", "Add beans and pasta. Simmer for 10 minutes.", "Add kale and cook until wilted, about 3 minutes.", "Season with salt, pepper, and a drizzle of olive oil to serve."] },
  { title: "Eggplant Parmigiana", description: "Layers of fried eggplant with marinara sauce, mozzarella, and Parmesan baked until bubbly.", cuisine: "Italian", diet: ["Vegetarian"], cookTimeMinutes: 60, servings: 6, ingredients: ["3 large eggplants, sliced 1cm thick", "500ml marinara sauce", "300g mozzarella, sliced", "100g Parmesan, grated", "100g breadcrumbs", "3 eggs, beaten", "Fresh basil", "Olive oil for frying"], instructions: ["Salt eggplant slices and let drain for 30 minutes. Pat dry.", "Dip slices in egg, then breadcrumbs. Fry until golden on both sides.", "Spread a thin layer of marinara in a baking dish.", "Layer fried eggplant, marinara, mozzarella, and Parmesan.", "Repeat layers, finishing with sauce and Parmesan on top.", "Bake at 180°C for 25 minutes until bubbly and golden.", "Rest 10 minutes, garnish with basil before serving."] },

  // === INDIAN ===
  { title: "Chicken Tikka Masala", description: "Tender chicken pieces in a creamy spiced tomato sauce, a beloved British-Indian classic.", cuisine: "Indian", diet: ["Gluten-Free"], cookTimeMinutes: 45, servings: 4, ingredients: ["600g chicken thighs, cubed", "200g yogurt", "2 tbsp garam masala", "400g tomato puree", "200ml heavy cream", "2 tbsp fresh ginger, grated", "4 garlic cloves, minced", "2 tsp cumin", "1 tsp turmeric", "2 tbsp butter"], instructions: ["Marinate chicken in yogurt, 1 tbsp garam masala, and salt for 1 hour.", "Grill or pan-fry chicken until charred. Set aside.", "Sauté ginger and garlic in butter for 1 minute.", "Add remaining spices and cook 30 seconds until fragrant.", "Pour in tomato puree and simmer 15 minutes.", "Stir in cream and remaining garam masala.", "Add chicken pieces and simmer 10 minutes. Serve with naan or rice."] },
  { title: "Butter Chicken", description: "Tender tandoori chicken in a velvety tomato-butter sauce with aromatic spices and cream.", cuisine: "Indian", diet: ["Gluten-Free"], cookTimeMinutes: 50, servings: 4, ingredients: ["600g chicken, cubed", "80g butter", "400g tomato puree", "200ml cream", "2 tbsp garam masala", "1 tbsp dried fenugreek leaves", "2 tbsp ginger-garlic paste", "1 tsp chili powder", "1 tsp sugar", "Salt to taste"], instructions: ["Marinate chicken in yogurt and spices for 30 minutes.", "Cook chicken in a hot pan until browned.", "Melt butter in a separate pan. Add ginger-garlic paste and cook 1 minute.", "Add tomato puree and simmer 20 minutes until thickened.", "Blend sauce until smooth, return to pan.", "Add cream, sugar, fenugreek, and garam masala.", "Add chicken and simmer 10 minutes. Finish with a swirl of cream."] },
  { title: "Palak Paneer", description: "Cubes of fresh paneer cheese in a vibrant spinach sauce spiced with cumin and garam masala.", cuisine: "Indian", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 35, servings: 4, ingredients: ["300g paneer, cubed", "500g fresh spinach", "1 onion, diced", "2 tomatoes, chopped", "2 tsp cumin seeds", "1 tbsp garam masala", "3 tbsp cream", "3 garlic cloves, minced", "1 inch ginger, grated", "2 green chilies"], instructions: ["Blanch spinach in boiling water for 2 minutes. Plunge into ice water.", "Blend spinach into a smooth puree.", "Fry paneer cubes until golden. Set aside.", "Sauté cumin seeds, then add onion and cook until golden.", "Add ginger, garlic, chilies, and tomatoes. Cook 5 minutes.", "Add spinach puree and garam masala. Simmer 10 minutes.", "Fold in paneer cubes and cream. Serve with roti."] },
  { title: "Chana Masala", description: "Spiced chickpea curry in a tangy tomato-onion sauce — a North Indian staple.", cuisine: "Indian", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["2 cans chickpeas, drained", "3 tomatoes, pureed", "2 onions, finely diced", "2 tsp cumin seeds", "2 tsp coriander powder", "1 tsp amchur (dried mango powder)", "1 tsp garam masala", "4 garlic cloves, minced", "1 inch ginger, grated", "2 tbsp oil"], instructions: ["Heat oil and add cumin seeds until they splutter.", "Add onions and cook until deep golden, about 10 minutes.", "Add ginger, garlic, and all spices. Cook 1 minute.", "Pour in tomato puree and cook until oil separates, about 8 minutes.", "Add chickpeas and 1 cup water. Simmer 15 minutes.", "Finish with amchur and garam masala. Garnish with cilantro."] },
  { title: "Biryani", description: "Fragrant basmati rice layered with spiced meat, caramelized onions, and saffron.", cuisine: "Indian", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 90, servings: 6, ingredients: ["500g basmati rice, soaked 30 min", "500g lamb, cubed", "3 onions, thinly sliced", "200g yogurt", "1 pinch saffron in 3 tbsp warm milk", "6 cardamom pods", "4 cinnamon sticks", "6 bay leaves", "2 tbsp ginger-garlic paste", "Fresh mint and cilantro"], instructions: ["Fry onions until deep golden brown. Remove half for garnish.", "Add lamb to remaining onions with yogurt and ginger-garlic paste. Cook 20 minutes.", "Parboil rice with whole spices until 70% cooked. Drain.", "Layer rice over the meat in a heavy pot.", "Drizzle saffron milk over rice. Top with fried onions, mint, and cilantro.", "Seal pot with foil and lid. Cook on lowest heat for 25 minutes.", "Rest 5 minutes, then gently mix layers when serving."] },
  { title: "Samosas", description: "Crispy fried pastry triangles stuffed with spiced potatoes and peas.", cuisine: "Indian", diet: ["Vegan", "Dairy-Free"], cookTimeMinutes: 45, servings: 12, ingredients: ["3 large potatoes, boiled and mashed", "1 cup peas", "250g all-purpose flour", "2 tsp cumin seeds", "1 tsp coriander powder", "2 green chilies, minced", "1 inch ginger, grated", "Oil for deep frying", "Salt to taste"], instructions: ["Make dough: mix flour, salt, 2 tbsp oil, and water. Rest 30 minutes.", "Sauté cumin seeds, add ginger and chilies.", "Add mashed potatoes, peas, and spices. Mix well and cool.", "Roll dough into circles, cut in half. Form cones and fill with potato mixture.", "Seal edges with water.", "Deep fry at 170°C until golden and crispy, about 5 minutes.", "Serve with mint chutney and tamarind sauce."] },
  { title: "Dal Tadka", description: "Comforting yellow lentils tempered with cumin, garlic, and dried red chilies.", cuisine: "Indian", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["1 cup yellow lentils (toor dal)", "1 tsp cumin seeds", "4 garlic cloves, sliced", "3 dried red chilies", "1 tsp turmeric", "2 tomatoes, chopped", "Fresh cilantro", "2 tbsp oil or ghee", "Salt to taste"], instructions: ["Wash lentils and cook with turmeric and 3 cups water until soft (20 minutes).", "Mash lentils slightly and add salt.", "For tadka: heat oil in a small pan until very hot.", "Add cumin seeds, dried chilies, and sliced garlic.", "When garlic turns golden (30 seconds), add chopped tomatoes.", "Cook 2 minutes, then pour the sizzling tadka over the dal.", "Garnish with cilantro and serve with rice."] },
  { title: "Tandoori Chicken", description: "Yogurt-marinated chicken roasted in a clay oven until charred and smoky.", cuisine: "Indian", diet: ["Gluten-Free"], cookTimeMinutes: 40, servings: 4, ingredients: ["1 whole chicken, cut into pieces", "250g yogurt", "3 tbsp tandoori masala", "2 tbsp lemon juice", "2 tbsp ginger-garlic paste", "1 tsp Kashmiri chili powder", "Salt to taste", "Butter for basting", "Lemon wedges and onion rings to serve"], instructions: ["Score chicken pieces deeply with a knife.", "Mix yogurt, tandoori masala, lemon juice, ginger-garlic paste, and chili powder.", "Coat chicken thoroughly. Marinate for 4+ hours (overnight is best).", "Preheat oven to 220°C. Place chicken on a wire rack over a tray.", "Roast for 25-30 minutes, basting with butter halfway through.", "Finish under the grill for 3 minutes for char.", "Serve with lemon wedges and onion rings."] },

  // === THAI ===
  { title: "Pad Thai", description: "Stir-fried rice noodles with shrimp, tofu, peanuts, and tamarind sauce — Thailand's most famous street food.", cuisine: "Thai", diet: [], cookTimeMinutes: 30, servings: 4, ingredients: ["250g flat rice noodles, soaked", "200g shrimp, peeled", "150g firm tofu, cubed", "100g bean sprouts", "50g roasted peanuts, crushed", "3 tbsp tamarind paste", "2 tbsp fish sauce", "1 tbsp sugar", "2 eggs", "4 garlic cloves, minced", "Lime wedges"], instructions: ["Soak noodles in warm water for 30 minutes until pliable. Drain.", "Mix tamarind paste, fish sauce, and sugar for the sauce.", "Heat oil in a wok over high heat. Cook shrimp until pink. Remove.", "Fry tofu until golden. Add garlic and cook 30 seconds.", "Push everything aside, scramble eggs in the center.", "Add noodles and sauce. Toss vigorously for 2 minutes.", "Return shrimp, add bean sprouts. Toss briefly.", "Serve topped with crushed peanuts and lime wedges."] },
  { title: "Tom Yum Soup", description: "A hot and sour Thai soup with shrimp, mushrooms, lemongrass, and kaffir lime leaves.", cuisine: "Thai", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 20, servings: 4, ingredients: ["300g shrimp, peeled", "3 stalks lemongrass, bruised", "5 slices galangal", "5 kaffir lime leaves, torn", "200g mushrooms, halved", "3 Thai chilies, crushed", "3 tbsp fish sauce", "3 tbsp lime juice", "1L chicken broth", "Fresh cilantro"], instructions: ["Bring broth to a boil with lemongrass, galangal, and lime leaves.", "Simmer 5 minutes to infuse flavors.", "Add mushrooms and cook 3 minutes.", "Add shrimp and chilies. Cook until shrimp turn pink (2 minutes).", "Remove from heat. Stir in fish sauce and lime juice.", "Taste and adjust — should be sour, salty, and spicy.", "Garnish with cilantro and serve immediately."] },
  { title: "Green Curry", description: "Thai green curry with coconut milk, bamboo shoots, Thai basil, and your choice of protein.", cuisine: "Thai", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["400ml coconut milk", "3 tbsp green curry paste", "400g chicken thighs, sliced", "200g bamboo shoots", "1 cup Thai basil leaves", "2 tbsp fish sauce", "1 tbsp palm sugar", "3 kaffir lime leaves", "2 Thai eggplants, quartered", "Jasmine rice to serve"], instructions: ["Heat thick coconut cream (top of can) in a wok until it splits.", "Fry curry paste in the cream for 2 minutes until fragrant.", "Add chicken and cook 5 minutes until sealed.", "Pour in remaining coconut milk, fish sauce, and palm sugar.", "Add bamboo shoots, eggplant, and lime leaves. Simmer 10 minutes.", "Stir in Thai basil just before serving.", "Serve over jasmine rice."] },
  { title: "Massaman Curry", description: "Rich and mild Thai curry with potatoes, peanuts, and warm spices influenced by Indian cuisine.", cuisine: "Thai", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 50, servings: 4, ingredients: ["400ml coconut milk", "3 tbsp massaman curry paste", "500g beef chuck, cubed", "3 potatoes, cubed", "50g roasted peanuts", "2 tbsp tamarind paste", "2 tbsp palm sugar", "1 cinnamon stick", "3 cardamom pods", "2 tbsp fish sauce"], instructions: ["Simmer thick coconut cream with curry paste for 3 minutes.", "Add beef and sear on all sides.", "Pour in remaining coconut milk. Add cinnamon and cardamom.", "Simmer 30 minutes until beef is tender.", "Add potatoes and cook 15 more minutes.", "Stir in tamarind, palm sugar, fish sauce, and peanuts.", "Serve with steamed jasmine rice."] },
  { title: "Som Tum (Green Papaya Salad)", description: "Spicy and tangy shredded green papaya salad with tomatoes, peanuts, and dried shrimp.", cuisine: "Thai", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 15, servings: 2, ingredients: ["2 cups green papaya, shredded", "6 cherry tomatoes, halved", "2 tbsp roasted peanuts", "1 tbsp dried shrimp", "3 tbsp lime juice", "2 tbsp fish sauce", "3 Thai chilies", "3 garlic cloves", "1 tbsp palm sugar", "1 long bean, cut into 2-inch pieces"], instructions: ["Pound garlic and chilies in a mortar until crushed.", "Add long beans and bruise lightly.", "Add palm sugar, fish sauce, and lime juice. Mix.", "Add tomatoes and pound gently to release juices.", "Add shredded papaya and toss (don't pound) to coat.", "Add peanuts and dried shrimp. Toss once more.", "Serve immediately on a plate with sticky rice."] },
  { title: "Mango Sticky Rice", description: "Sweet coconut sticky rice served with fresh ripe mango slices — Thailand's beloved dessert.", cuisine: "Thai", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 40, servings: 4, ingredients: ["2 cups sticky (glutinous) rice, soaked overnight", "400ml coconut milk", "100g sugar", "1/2 tsp salt", "2 ripe mangoes, sliced", "Toasted sesame seeds for garnish"], instructions: ["Steam soaked sticky rice for 20 minutes until tender.", "Heat coconut milk with sugar and salt until dissolved (don't boil).", "Pour 2/3 of the coconut sauce over hot rice. Stir and let absorb 15 minutes.", "Slice mangoes and arrange on plates.", "Mound sticky rice next to mango.", "Drizzle remaining coconut sauce on top. Sprinkle with sesame seeds."] },
  { title: "Pad Kra Pao", description: "Stir-fried holy basil with minced pork, chili, garlic, and a fried egg on rice.", cuisine: "Thai", diet: ["Dairy-Free"], cookTimeMinutes: 15, servings: 2, ingredients: ["300g minced pork", "2 cups holy basil leaves", "5 garlic cloves, minced", "5 Thai chilies, minced", "2 tbsp soy sauce", "1 tbsp oyster sauce", "1 tsp sugar", "2 eggs", "Steamed jasmine rice"], instructions: ["Heat oil in a wok until smoking hot.", "Fry garlic and chilies for 30 seconds.", "Add minced pork, break apart, and cook on high heat 3 minutes.", "Add soy sauce, oyster sauce, and sugar. Stir-fry 1 minute.", "Throw in basil leaves and toss until just wilted (10 seconds).", "Fry eggs separately until edges are crispy.", "Serve pork over rice, topped with fried egg."] },

  // === JAPANESE ===
  { title: "Sushi Rolls (Maki)", description: "Hand-rolled sushi with seasoned rice, fresh fish, and vegetables wrapped in nori seaweed.", cuisine: "Japanese", diet: ["Dairy-Free"], cookTimeMinutes: 60, servings: 4, ingredients: ["2 cups sushi rice", "4 sheets nori seaweed", "200g sashimi-grade salmon, sliced", "1 avocado, sliced", "1 cucumber, julienned", "3 tbsp rice vinegar", "1 tbsp sugar", "Wasabi and soy sauce to serve"], instructions: ["Rinse rice until water runs clear. Cook and season with rice vinegar, sugar, and salt while warm.", "Place a nori sheet on a bamboo mat, shiny side down.", "Spread a thin layer of rice over the nori, leaving a 1cm border at the top.", "Lay salmon, avocado, and cucumber in a line across the center.", "Roll tightly using the bamboo mat, sealing the edge with water.", "Slice each roll into 8 pieces with a wet knife.", "Serve with wasabi, soy sauce, and pickled ginger."] },
  { title: "Ramen (Tonkotsu)", description: "Rich pork bone broth ramen with chashu pork, soft-boiled egg, nori, and green onions.", cuisine: "Japanese", diet: ["Dairy-Free"], cookTimeMinutes: 240, servings: 4, ingredients: ["1.5kg pork bones, split", "4 portions fresh ramen noodles", "300g pork belly for chashu", "4 soft-boiled eggs, marinated", "4 sheets nori", "4 green onions, sliced", "4 tbsp soy sauce", "2 tbsp mirin"], instructions: ["Blanch pork bones in boiling water for 10 minutes. Drain and rinse.", "Cover bones with fresh water and boil vigorously for 8-12 hours, adding water as needed, until broth is milky white.", "Make chashu: roll pork belly, braise in soy sauce, mirin, and sake for 2 hours until tender. Slice.", "Marinate soft-boiled eggs in soy-mirin mixture for 4+ hours.", "Season broth with soy sauce and salt to taste.", "Cook noodles according to package directions. Divide into bowls.", "Ladle hot broth over noodles. Top with chashu, halved egg, nori, and green onions."] },
  { title: "Tempura", description: "Light and crispy battered shrimp and vegetables served with tentsuyu dipping sauce.", cuisine: "Japanese", diet: ["Dairy-Free"], cookTimeMinutes: 25, servings: 4, ingredients: ["12 large shrimp, peeled and deveined", "1 sweet potato, sliced 5mm thick", "100g green beans, trimmed", "100g all-purpose flour", "1 egg yolk", "200ml ice-cold sparkling water", "200ml dashi stock", "3 tbsp soy sauce", "2 tbsp mirin"], instructions: ["Make tentsuyu: combine dashi, soy sauce, and mirin. Warm gently.", "Heat oil to 180°C in a deep pot.", "Mix flour, egg yolk, and ice water briefly — batter should be lumpy.", "Dip shrimp and vegetables in batter, letting excess drip off.", "Fry in small batches for 2-3 minutes until light golden and crispy.", "Drain on a wire rack. Serve immediately with tentsuyu dipping sauce."] },
  { title: "Teriyaki Salmon", description: "Glazed salmon fillets with a sweet and savory teriyaki sauce, served over steamed rice.", cuisine: "Japanese", diet: ["Dairy-Free", "Gluten-Free"], cookTimeMinutes: 20, servings: 2, ingredients: ["2 salmon fillets (180g each)", "3 tbsp soy sauce", "2 tbsp mirin", "1 tbsp sake", "1 tbsp sugar", "1 tsp fresh ginger, grated", "2 cups steamed rice", "1 tsp sesame seeds"], instructions: ["Mix soy sauce, mirin, sake, and sugar to make teriyaki sauce.", "Pat salmon dry and season with salt.", "Sear salmon skin-side down in a hot pan for 3 minutes.", "Flip and cook 2 more minutes.", "Pour teriyaki sauce into the pan and simmer until it thickens and glazes the fish.", "Serve over steamed rice, drizzled with remaining sauce and sprinkled with sesame seeds."] },
  { title: "Miso Soup", description: "Simple and comforting Japanese soup with tofu, wakame seaweed, and green onions in dashi broth.", cuisine: "Japanese", diet: ["Vegan", "Dairy-Free"], cookTimeMinutes: 10, servings: 4, ingredients: ["3 tbsp white miso paste", "200g silken tofu, cubed", "2 tbsp dried wakame seaweed", "800ml dashi stock", "2 green onions, thinly sliced"], instructions: ["Bring dashi stock to a gentle simmer (do not boil).", "Soak wakame in warm water for 5 minutes. Drain.", "Add tofu cubes and wakame to the broth.", "Remove a ladleful of broth and dissolve miso paste into it.", "Stir dissolved miso back into the pot. Do not boil after adding miso.", "Serve immediately, garnished with sliced green onions."] },
  { title: "Okonomiyaki", description: "Savory Japanese cabbage pancake topped with mayo, okonomiyaki sauce, and bonito flakes.", cuisine: "Japanese", diet: [], cookTimeMinutes: 25, servings: 2, ingredients: ["300g cabbage, finely shredded", "100g all-purpose flour", "2 eggs", "100ml dashi stock", "100g pork belly, thinly sliced", "3 tbsp okonomiyaki sauce", "2 tbsp Japanese mayo", "Bonito flakes for topping"], instructions: ["Mix flour, dashi, and eggs into a batter. Fold in shredded cabbage.", "Heat oil in a large pan over medium heat.", "Pour half the batter into the pan, forming a thick pancake. Lay pork slices on top.", "Cook 4 minutes until bottom is golden. Flip carefully.", "Cook another 4 minutes until pork is crispy and pancake is cooked through.", "Top with okonomiyaki sauce, mayo in zigzag lines, and bonito flakes.", "Repeat with remaining batter. Serve hot."] },
  { title: "Gyoza", description: "Pan-fried Japanese dumplings with a juicy pork and cabbage filling and crispy bottom.", cuisine: "Japanese", diet: ["Dairy-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["250g ground pork", "200g cabbage, finely minced and squeezed dry", "2 garlic cloves, minced", "1 tbsp fresh ginger, grated", "2 tbsp soy sauce", "1 tbsp sesame oil", "30 gyoza wrappers", "Rice vinegar and chili oil for dipping"], instructions: ["Mix pork, cabbage, garlic, ginger, soy sauce, and sesame oil.", "Place a teaspoon of filling in the center of each wrapper.", "Fold in half and pleat the edges to seal.", "Heat oil in a non-stick pan. Place gyoza flat-side down in rows.", "Fry for 2 minutes until bottoms are golden.", "Add 60ml water and cover. Steam for 5 minutes until water evaporates.", "Serve crispy-side up with soy-vinegar dipping sauce."] },

  // === MEXICAN ===
  { title: "Tacos al Pastor", description: "Marinated pork tacos with pineapple, cilantro, and onion on soft corn tortillas — Mexico City street food.", cuisine: "Mexican", diet: ["Dairy-Free"], cookTimeMinutes: 40, servings: 4, ingredients: ["500g pork shoulder, thinly sliced", "200g fresh pineapple, diced", "12 small corn tortillas", "1/2 cup fresh cilantro, chopped", "1 white onion, finely diced", "3 tbsp achiote paste", "2 limes, cut into wedges", "3 dried guajillo chilies"], instructions: ["Blend achiote paste with rehydrated guajillo chilies, pineapple juice, and vinegar to make marinade.", "Coat pork slices in marinade and refrigerate for 2+ hours.", "Grill or pan-fry pork over high heat until charred at edges, about 3 minutes per side.", "Grill pineapple slices until caramelized. Dice.", "Chop pork into small pieces.", "Warm tortillas on a dry griddle.", "Assemble tacos with pork, pineapple, onion, cilantro, and a squeeze of lime."] },
  { title: "Guacamole", description: "Fresh avocado dip with lime, cilantro, onion, and jalapeño — the perfect party starter.", cuisine: "Mexican", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 10, servings: 4, ingredients: ["3 ripe avocados", "2 tbsp fresh lime juice", "1/4 cup fresh cilantro, chopped", "1/4 red onion, finely diced", "1 jalapeño, seeded and minced", "1 Roma tomato, diced", "Salt to taste"], instructions: ["Halve avocados and remove pits. Scoop flesh into a bowl.", "Mash with a fork to desired consistency (leave some chunks).", "Stir in lime juice, cilantro, onion, jalapeño, and tomato.", "Season with salt and taste — adjust lime and salt as needed.", "Serve immediately with tortilla chips."] },
  { title: "Enchiladas Verdes", description: "Corn tortillas filled with chicken, rolled and smothered in tangy tomatillo salsa verde.", cuisine: "Mexican", diet: ["Gluten-Free"], cookTimeMinutes: 40, servings: 4, ingredients: ["12 corn tortillas", "400g cooked chicken, shredded", "500g tomatillos, husked", "2 jalapeños, halved", "150ml sour cream", "150g queso fresco, crumbled", "1/2 white onion, chopped", "1/4 cup fresh cilantro"], instructions: ["Roast tomatillos, jalapeños, and onion under a grill until charred.", "Blend roasted vegetables with cilantro and salt until smooth.", "Warm tortillas briefly in oil to soften.", "Fill each tortilla with shredded chicken and roll tightly.", "Place seam-side down in a baking dish. Pour salsa verde over the top.", "Bake at 180°C for 15 minutes until bubbling.", "Top with sour cream and crumbled queso fresco before serving."] },
  { title: "Elote (Mexican Street Corn)", description: "Grilled corn on the cob slathered with mayo, cotija cheese, chili powder, and lime.", cuisine: "Mexican", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 15, servings: 4, ingredients: ["4 ears of corn, husked", "3 tbsp mayonnaise", "60g cotija cheese, crumbled", "1 tsp chili powder", "2 limes, cut into wedges", "2 tbsp fresh cilantro, chopped", "1 tbsp butter, melted"], instructions: ["Grill corn over high heat, turning frequently, until charred in spots (about 8 minutes).", "Brush each ear with mayonnaise while still hot.", "Sprinkle generously with cotija cheese and chili powder.", "Squeeze lime juice over the top.", "Garnish with cilantro and serve immediately."] },
  { title: "Pozole Rojo", description: "Hearty Mexican hominy soup with pork in a rich red chili broth, topped with cabbage and radish.", cuisine: "Mexican", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 120, servings: 6, ingredients: ["800g canned hominy, drained", "600g pork shoulder, cubed", "6 dried guajillo chilies, stemmed and seeded", "4 garlic cloves", "1 white onion, quartered", "1 tbsp dried oregano", "Shredded cabbage for topping", "Sliced radishes for topping"], instructions: ["Simmer pork in salted water for 1 hour until tender. Reserve broth.", "Toast dried chilies in a dry pan for 30 seconds per side.", "Soak chilies in hot water for 15 minutes. Blend with garlic and onion until smooth.", "Strain chili sauce into the pork broth.", "Add hominy and shredded pork. Simmer 30 minutes.", "Season with oregano and salt.", "Serve in bowls topped with shredded cabbage, radishes, and lime wedges."] },
  { title: "Churros", description: "Crispy fried dough sticks coated in cinnamon sugar, served with thick chocolate dipping sauce.", cuisine: "Mexican", diet: ["Vegetarian"], cookTimeMinutes: 30, servings: 6, ingredients: ["125g all-purpose flour", "60g butter", "1 cup water", "2 eggs", "100g sugar mixed with 2 tsp cinnamon", "Oil for deep frying", "150g dark chocolate, chopped", "100ml whole milk"], instructions: ["Heat water and butter in a saucepan until boiling.", "Add flour all at once and stir vigorously until dough forms a ball.", "Cool slightly, then beat in eggs one at a time until smooth.", "Transfer dough to a piping bag with a star tip.", "Heat oil to 180°C. Pipe 10cm strips directly into oil.", "Fry until golden brown, about 3-4 minutes. Drain on paper towels.", "Roll warm churros in cinnamon sugar. Melt chocolate with milk for dipping sauce."] },
  { title: "Black Bean Tacos", description: "Smoky spiced black beans in warm tortillas with pickled onion, avocado, and cotija cheese.", cuisine: "Mexican", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 20, servings: 4, ingredients: ["2 cans black beans, drained", "8 corn tortillas", "1 avocado, sliced", "1/2 red onion, pickled in lime juice", "60g cotija cheese, crumbled", "1 tsp cumin", "1 tsp smoked paprika", "1 lime, cut into wedges"], instructions: ["Heat beans in a pan with cumin, smoked paprika, and a splash of water.", "Mash half the beans roughly, leaving some whole for texture.", "Warm tortillas on a dry griddle until pliable.", "Spoon beans onto tortillas.", "Top with avocado slices, pickled onion, and crumbled cotija.", "Squeeze lime over the top and serve."] },

  // === FRENCH ===
  { title: "Beef Bourguignon", description: "A rich French stew of beef braised in red wine with mushrooms, pearl onions, and bacon.", cuisine: "French", diet: [], cookTimeMinutes: 180, servings: 6, ingredients: ["1kg beef chuck, cut into 5cm cubes", "750ml red Burgundy wine", "200g cremini mushrooms, quartered", "200g pearl onions, peeled", "150g thick-cut bacon, diced", "3 carrots, sliced", "4 sprigs fresh thyme", "2 bay leaves"], instructions: ["Sear bacon in a Dutch oven until crispy. Remove and set aside.", "Brown beef cubes in batches in the bacon fat. Remove.", "Sauté carrots and pearl onions for 5 minutes.", "Return beef and bacon. Pour in wine and enough broth to cover.", "Add thyme and bay leaves. Bring to a simmer.", "Cover and braise in a 160°C oven for 2.5 hours.", "Add mushrooms in the last 30 minutes. Season and serve with crusty bread."] },
  { title: "Chocolate Lava Cake", description: "Individual warm chocolate cakes with a molten center, served with vanilla ice cream.", cuisine: "French", diet: ["Vegetarian"], cookTimeMinutes: 20, servings: 4, ingredients: ["200g dark chocolate (70%), chopped", "100g butter, plus extra for greasing", "3 eggs", "80g sugar", "2 tbsp all-purpose flour", "1 tsp vanilla extract"], instructions: ["Preheat oven to 220°C. Butter and flour 4 ramekins.", "Melt chocolate and butter together over a double boiler. Cool slightly.", "Whisk eggs and sugar until thick and pale (3 minutes).", "Fold chocolate mixture into eggs, then fold in flour and vanilla.", "Divide batter among ramekins.", "Bake for 10-12 minutes until edges are set but center jiggles.", "Invert onto plates immediately and serve with vanilla ice cream."] },
  { title: "Coq au Vin", description: "Chicken braised in red wine with mushrooms, lardons, and pearl onions — rustic French comfort food.", cuisine: "French", diet: ["Gluten-Free"], cookTimeMinutes: 120, servings: 4, ingredients: ["1 whole chicken, cut into 8 pieces", "500ml red wine", "200g cremini mushrooms, halved", "150g lardons (thick bacon)", "150g pearl onions, peeled", "4 garlic cloves, crushed", "4 sprigs fresh thyme", "2 bay leaves"], instructions: ["Marinate chicken in wine with thyme and bay leaves overnight (or 4 hours minimum).", "Remove chicken and pat dry. Reserve marinade.", "Brown lardons in a Dutch oven. Remove. Brown chicken pieces in the fat.", "Sauté pearl onions and garlic for 3 minutes.", "Return chicken and lardons. Pour in reserved marinade.", "Cover and simmer on low heat for 1.5 hours.", "Add mushrooms in the last 20 minutes. Reduce sauce if needed and serve."] },
  { title: "French Onion Soup", description: "Caramelized onion soup topped with crusty bread and melted Gruyère cheese.", cuisine: "French", diet: ["Vegetarian"], cookTimeMinutes: 60, servings: 4, ingredients: ["5 large onions, thinly sliced", "50g butter", "1L beef or vegetable broth", "150ml dry white wine", "4 slices baguette, toasted", "200g Gruyère cheese, grated", "3 sprigs fresh thyme"], instructions: ["Melt butter in a large pot. Add onions and cook on medium-low for 40 minutes, stirring occasionally, until deep golden brown.", "Add white wine and scrape up any browned bits. Simmer until reduced by half.", "Add broth and thyme. Simmer 15 minutes. Season with salt and pepper.", "Ladle soup into oven-safe bowls.", "Top each with a baguette slice and generous Gruyère.", "Broil until cheese is bubbly and golden, about 3 minutes."] },
  { title: "Crêpes Suzette", description: "Thin French pancakes flambéed in orange butter sauce with Grand Marnier.", cuisine: "French", diet: ["Vegetarian"], cookTimeMinutes: 30, servings: 4, ingredients: ["125g all-purpose flour", "2 eggs", "250ml whole milk", "50g butter, melted, plus 60g for sauce", "100ml fresh orange juice", "Zest of 1 orange", "60g sugar", "3 tbsp Grand Marnier"], instructions: ["Blend flour, eggs, milk, and melted butter until smooth. Rest 30 minutes.", "Cook thin crêpes in a buttered pan (about 8 crêpes).", "For sauce: melt 60g butter with sugar and orange zest until caramelized.", "Add orange juice and simmer until syrupy.", "Fold crêpes into quarters and place in the sauce.", "Add Grand Marnier and carefully ignite to flambé.", "Serve immediately once flames subside, spooning sauce over crêpes."] },
  { title: "Ratatouille", description: "Provençal vegetable stew with eggplant, zucchini, peppers, and tomatoes in herbed olive oil.", cuisine: "French", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 50, servings: 4, ingredients: ["1 large eggplant, diced", "2 zucchini, diced", "2 bell peppers, diced", "4 ripe tomatoes, chopped", "1 onion, diced", "4 garlic cloves, minced", "2 tsp herbes de Provence", "4 tbsp olive oil"], instructions: ["Heat olive oil in a large pan. Sauté onion and garlic for 3 minutes.", "Add bell peppers and cook 5 minutes.", "Add eggplant and zucchini. Cook 10 minutes, stirring occasionally.", "Add tomatoes and herbes de Provence. Season with salt and pepper.", "Cover and simmer on low heat for 25 minutes until all vegetables are tender.", "Adjust seasoning and drizzle with extra olive oil before serving."] },
  { title: "Quiche Lorraine", description: "Savory custard tart with bacon, Gruyère cheese, and caramelized onions in a flaky crust.", cuisine: "French", diet: [], cookTimeMinutes: 50, servings: 6, ingredients: ["1 sheet shortcrust pastry (or homemade pie crust)", "150g bacon, diced", "150g Gruyère cheese, grated", "4 eggs", "250ml heavy cream", "1 onion, thinly sliced", "Pinch of nutmeg"], instructions: ["Preheat oven to 190°C. Line a tart tin with pastry and blind bake for 10 minutes.", "Cook bacon until crispy. Caramelize onion in the bacon fat.", "Spread bacon, onion, and most of the Gruyère over the pastry base.", "Whisk eggs, cream, nutmeg, salt, and pepper together.", "Pour custard over the filling. Top with remaining cheese.", "Bake for 30-35 minutes until set and golden on top.", "Rest 10 minutes before slicing."] },

  // === KOREAN ===
  { title: "Bibimbap", description: "Korean mixed rice bowl topped with sautéed vegetables, gochujang, a fried egg, and sesame oil.", cuisine: "Korean", diet: ["Vegetarian"], cookTimeMinutes: 40, servings: 2, ingredients: ["2 cups cooked short-grain rice", "100g fresh spinach, blanched", "1 carrot, julienned", "1 zucchini, julienned", "100g shiitake mushrooms, sliced", "2 tbsp gochujang", "2 tsp sesame oil", "2 eggs"], instructions: ["Sauté each vegetable separately with a pinch of salt and sesame oil.", "Season spinach with soy sauce and sesame oil after blanching.", "Divide hot rice into 2 bowls.", "Arrange vegetables in sections on top of the rice.", "Fry eggs sunny-side up.", "Place egg on top of each bowl. Add a generous spoonful of gochujang.", "Drizzle with sesame oil. Mix everything together before eating."] },
  { title: "Kimchi Fried Rice", description: "Spicy stir-fried rice with aged kimchi, pork belly, and a crispy fried egg on top.", cuisine: "Korean", diet: ["Dairy-Free"], cookTimeMinutes: 15, servings: 2, ingredients: ["3 cups day-old cooked rice", "200g aged kimchi, chopped (reserve juice)", "150g pork belly, thinly sliced", "2 eggs", "1 tbsp sesame oil", "1 tbsp gochujang", "2 green onions, sliced", "1 tsp sesame seeds"], instructions: ["Cook pork belly in a hot wok until crispy and fat renders out.", "Add chopped kimchi and stir-fry for 2 minutes.", "Add rice and gochujang. Stir-fry on high heat for 3 minutes, breaking up clumps.", "Splash in kimchi juice for extra flavor. Toss well.", "Fry eggs separately until edges are crispy but yolk is runny.", "Plate rice, top with fried egg, green onions, and sesame seeds."] },
  { title: "Korean Fried Chicken", description: "Double-fried chicken wings tossed in a sweet and spicy gochujang glaze.", cuisine: "Korean", diet: ["Dairy-Free"], cookTimeMinutes: 45, servings: 4, ingredients: ["1kg chicken wings", "3 tbsp gochujang", "2 tbsp soy sauce", "3 tbsp honey", "4 garlic cloves, minced", "1 tbsp fresh ginger, grated", "100g cornstarch", "1 tbsp sesame seeds"], instructions: ["Toss wings in cornstarch and salt until evenly coated.", "Fry wings at 160°C for 10 minutes. Remove and rest 5 minutes.", "Fry again at 180°C for 8 minutes until extra crispy.", "Make sauce: simmer gochujang, soy sauce, honey, garlic, and ginger for 3 minutes.", "Toss crispy wings in the sauce until evenly coated.", "Sprinkle with sesame seeds and serve immediately."] },
  { title: "Japchae", description: "Stir-fried glass noodles with vegetables, beef, and sesame-soy sauce — a Korean celebration dish.", cuisine: "Korean", diet: ["Dairy-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["200g sweet potato glass noodles", "150g beef sirloin, thinly sliced", "100g fresh spinach, blanched", "1 carrot, julienned", "100g shiitake mushrooms, sliced", "3 tbsp soy sauce", "2 tbsp sesame oil", "2 garlic cloves, minced"], instructions: ["Cook noodles according to package. Drain and cut into shorter lengths.", "Marinate beef in 1 tbsp soy sauce and garlic for 10 minutes.", "Stir-fry beef over high heat until browned. Remove.", "Sauté carrots and mushrooms separately until tender.", "Combine noodles, beef, all vegetables, remaining soy sauce, and sesame oil in a large pan.", "Toss over medium heat for 2 minutes until everything is well combined.", "Serve warm or at room temperature, garnished with sesame seeds."] },
  { title: "Tteokbokki", description: "Chewy rice cakes in a fiery gochujang sauce with fish cakes and green onions.", cuisine: "Korean", diet: ["Dairy-Free"], cookTimeMinutes: 20, servings: 3, ingredients: ["400g Korean rice cakes (tteok)", "3 tbsp gochujang", "100g fish cakes, sliced", "3 green onions, cut into 5cm pieces", "2 tbsp sugar", "1 tbsp soy sauce", "2 garlic cloves, minced", "400ml anchovy or dashi stock"], instructions: ["Soak rice cakes in warm water for 10 minutes if hardened.", "Bring stock to a boil in a wide pan.", "Stir in gochujang, soy sauce, sugar, and garlic until dissolved.", "Add rice cakes and simmer for 8 minutes, stirring occasionally.", "Add fish cakes and green onions. Cook 3 more minutes until sauce thickens.", "Serve hot, garnished with sesame seeds."] },
  { title: "Bulgogi", description: "Thinly sliced beef marinated in soy, sesame, and pear, grilled over high heat.", cuisine: "Korean", diet: ["Dairy-Free", "Gluten-Free"], cookTimeMinutes: 25, servings: 4, ingredients: ["500g beef sirloin, thinly sliced", "4 tbsp soy sauce", "2 tbsp sesame oil", "1/2 Asian pear, grated", "4 garlic cloves, minced", "1 tbsp fresh ginger, grated", "3 green onions, sliced", "2 tbsp sugar"], instructions: ["Mix soy sauce, sesame oil, grated pear, garlic, ginger, and sugar for marinade.", "Toss beef slices in marinade. Refrigerate for 2+ hours (overnight is best).", "Heat a grill or cast-iron pan to very high heat.", "Cook beef in batches for 1-2 minutes per side — don't overcrowd.", "Garnish with sliced green onions and sesame seeds.", "Serve with steamed rice and lettuce leaves for wrapping."] },

  // === MIDDLE EASTERN ===
  { title: "Falafel Bowl", description: "Crispy chickpea fritters served over hummus with tabbouleh, pickled vegetables, and tahini drizzle.", cuisine: "Middle Eastern", diet: ["Vegan", "Dairy-Free"], cookTimeMinutes: 35, servings: 4, ingredients: ["400g dried chickpeas, soaked overnight", "1 cup fresh parsley, chopped", "2 tsp cumin", "3 tbsp tahini", "2 tbsp lemon juice", "100g bulgur wheat, cooked", "2 tomatoes, diced", "1 cucumber, diced"], instructions: ["Drain soaked chickpeas and blend with parsley, cumin, garlic, and salt until coarse (not smooth).", "Form mixture into small patties. Refrigerate 30 minutes.", "Deep fry falafel at 180°C for 3-4 minutes until deep golden.", "Make tabbouleh: toss bulgur with tomatoes, cucumber, parsley, lemon juice, and olive oil.", "Spread hummus on plates. Arrange falafel and tabbouleh on top.", "Drizzle with tahini sauce and serve with pickled vegetables."] },
  { title: "Shakshuka", description: "Eggs poached in a spiced tomato and pepper sauce, served with crusty bread for dipping.", cuisine: "Middle Eastern", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 25, servings: 4, ingredients: ["6 eggs", "400g canned crushed tomatoes", "2 bell peppers, diced", "1 onion, diced", "2 tsp cumin", "2 tsp smoked paprika", "3 garlic cloves, minced", "60g feta cheese, crumbled"], instructions: ["Sauté onion and peppers in olive oil for 5 minutes until softened.", "Add garlic, cumin, and paprika. Cook 1 minute.", "Pour in tomatoes and simmer 10 minutes until thickened.", "Make 6 wells in the sauce. Crack an egg into each.", "Cover and cook on low heat for 5-7 minutes until whites are set but yolks are runny.", "Crumble feta over the top and serve in the pan with crusty bread."] },
  { title: "Hummus", description: "Creamy blended chickpea dip with tahini, lemon, and garlic — the ultimate mezze staple.", cuisine: "Middle Eastern", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 10, servings: 6, ingredients: ["2 cans chickpeas, drained (reserve liquid)", "4 tbsp tahini", "3 tbsp lemon juice", "2 garlic cloves", "3 tbsp extra virgin olive oil", "1 tsp cumin", "Salt to taste"], instructions: ["Blend chickpeas, tahini, lemon juice, garlic, and cumin in a food processor.", "Add reserved chickpea liquid (aquafaba) a tablespoon at a time until silky smooth.", "Season with salt and blend once more.", "Spread on a plate, creating a well in the center.", "Drizzle generously with olive oil and sprinkle with paprika and whole chickpeas."] },
  { title: "Shawarma", description: "Spiced meat carved from a rotating spit, served in pita with garlic sauce and pickled turnips.", cuisine: "Middle Eastern", diet: ["Dairy-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["600g chicken thighs, boneless", "2 tsp cumin", "1 tsp turmeric", "2 tsp paprika", "4 garlic cloves, minced", "4 pita breads", "100g pickled turnips", "4 tbsp garlic sauce (toum)"], instructions: ["Mix cumin, turmeric, paprika, garlic, olive oil, and lemon juice for marinade.", "Coat chicken thighs and marinate for 2+ hours.", "Cook chicken on a very hot grill or pan for 5-6 minutes per side until charred.", "Rest 5 minutes, then slice thinly against the grain.", "Warm pita breads on the grill.", "Assemble: spread garlic sauce on pita, add sliced chicken, pickled turnips, and fresh vegetables.", "Roll tightly and serve."] },
  { title: "Baba Ganoush", description: "Smoky roasted eggplant dip blended with tahini, lemon, and garlic.", cuisine: "Middle Eastern", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 40, servings: 4, ingredients: ["2 large eggplants", "3 tbsp tahini", "2 tbsp lemon juice", "2 garlic cloves, minced", "2 tbsp extra virgin olive oil", "2 tbsp fresh parsley, chopped", "1 tbsp pomegranate seeds"], instructions: ["Char eggplants directly over a gas flame or under a broiler, turning frequently, until skin is blackened and flesh is soft (15-20 minutes).", "Let cool, then peel off charred skin. Drain excess liquid from flesh.", "Mash eggplant flesh with a fork (don't over-blend — keep some texture).", "Stir in tahini, lemon juice, garlic, and salt.", "Spread on a plate, drizzle with olive oil.", "Garnish with parsley and pomegranate seeds."] },
  { title: "Lamb Kofta", description: "Grilled spiced lamb skewers with mint yogurt sauce and warm flatbread.", cuisine: "Middle Eastern", diet: [], cookTimeMinutes: 25, servings: 4, ingredients: ["500g ground lamb", "1 onion, grated", "1/4 cup fresh parsley, finely chopped", "2 tsp cumin", "2 tsp ground coriander", "200g Greek yogurt", "2 tbsp fresh mint, chopped", "4 flatbreads"], instructions: ["Mix ground lamb with grated onion, parsley, cumin, coriander, and salt.", "Form mixture around metal skewers into elongated sausage shapes.", "Grill over high heat for 3-4 minutes per side until charred outside and cooked through.", "Make sauce: mix yogurt with mint, lemon juice, and a pinch of salt.", "Warm flatbreads on the grill for 30 seconds per side.", "Serve kofta on flatbread with mint yogurt and fresh salad."] },

  // === AMERICAN ===
  { title: "Caesar Salad", description: "Crisp romaine lettuce with creamy Caesar dressing, croutons, and shaved Parmesan.", cuisine: "American", diet: ["Vegetarian"], cookTimeMinutes: 15, servings: 4, ingredients: ["2 heads romaine lettuce, chopped", "60g Parmesan, shaved", "2 cups croutons", "1 tsp anchovy paste", "2 garlic cloves, minced", "2 tbsp lemon juice", "1 egg yolk", "100ml extra virgin olive oil"], instructions: ["Whisk egg yolk, anchovy paste, garlic, and lemon juice together.", "Slowly drizzle in olive oil while whisking to emulsify into a creamy dressing.", "Season dressing with salt and pepper.", "Toss chopped romaine with dressing until evenly coated.", "Top with croutons and shaved Parmesan.", "Serve immediately."] },
  { title: "Avocado Toast", description: "Smashed avocado on sourdough with chili flakes, microgreens, and a poached egg.", cuisine: "American", diet: ["Vegetarian"], cookTimeMinutes: 10, servings: 2, ingredients: ["2 ripe avocados", "2 thick slices sourdough bread", "2 eggs", "1/2 tsp chili flakes", "1 tbsp lemon juice", "Handful of microgreens", "Flaky sea salt", "1 tbsp olive oil"], instructions: ["Toast sourdough slices until golden and crisp.", "Poach eggs in simmering water with a splash of vinegar for 3 minutes.", "Mash avocados with lemon juice, salt, and pepper.", "Spread mashed avocado thickly on each toast.", "Top with a poached egg, chili flakes, and microgreens.", "Drizzle with olive oil and finish with flaky salt."] },
  { title: "Eggs Benedict", description: "Poached eggs on English muffins with Canadian bacon and silky hollandaise sauce.", cuisine: "American", diet: [], cookTimeMinutes: 25, servings: 2, ingredients: ["4 eggs", "2 English muffins, split and toasted", "4 slices Canadian bacon", "100g butter, melted", "1 tbsp lemon juice", "2 egg yolks (for hollandaise)", "Pinch of cayenne pepper"], instructions: ["Make hollandaise: whisk egg yolks and lemon juice over a double boiler until thick.", "Slowly drizzle in melted butter while whisking until emulsified. Season with cayenne and salt.", "Toast English muffin halves and warm Canadian bacon in a pan.", "Poach eggs in gently simmering water for 3 minutes.", "Assemble: muffin, bacon, poached egg, and generous hollandaise.", "Serve immediately with a sprinkle of cayenne."] },
  { title: "BBQ Pulled Pork", description: "Slow-smoked pork shoulder shredded and tossed in tangy barbecue sauce, served on brioche buns.", cuisine: "American", diet: ["Dairy-Free"], cookTimeMinutes: 480, servings: 8, ingredients: ["2kg pork shoulder (bone-in)", "250ml BBQ sauce", "3 tbsp apple cider vinegar", "2 tbsp brown sugar", "2 tbsp smoked paprika", "1 tbsp garlic powder", "8 brioche buns", "Coleslaw to serve"], instructions: ["Mix paprika, garlic powder, brown sugar, salt, and pepper into a dry rub.", "Coat pork shoulder generously with the rub.", "Slow cook at 120°C for 7-8 hours until internal temperature reaches 95°C and meat pulls apart easily.", "Shred pork with two forks, discarding excess fat.", "Toss shredded pork with BBQ sauce and apple cider vinegar.", "Toast brioche buns and pile high with pulled pork.", "Top with coleslaw and serve."] },
  { title: "Clam Chowder", description: "Creamy New England soup with tender clams, potatoes, and bacon in a rich broth.", cuisine: "American", diet: [], cookTimeMinutes: 40, servings: 4, ingredients: ["500g fresh clams (or 2 cans chopped clams)", "3 medium potatoes, diced", "100g bacon, diced", "1 onion, diced", "2 celery stalks, diced", "250ml heavy cream", "30g butter", "3 sprigs fresh thyme"], instructions: ["Cook bacon in a large pot until crispy. Remove half for garnish.", "Add butter, onion, and celery to the pot. Sauté 5 minutes.", "Add potatoes and clam juice (or broth). Simmer 15 minutes until potatoes are tender.", "Add clams and cream. Heat gently for 5 minutes (don't boil).", "Season with thyme, salt, and white pepper.", "Serve in bowls topped with reserved crispy bacon and oyster crackers."] },
  { title: "Buffalo Wings", description: "Crispy fried chicken wings tossed in spicy cayenne butter sauce with blue cheese dip.", cuisine: "American", diet: ["Gluten-Free"], cookTimeMinutes: 35, servings: 4, ingredients: ["1kg chicken wings, split at joint", "100ml cayenne hot sauce", "60g butter, melted", "1 tsp garlic powder", "100g blue cheese, crumbled", "4 celery stalks, cut into sticks", "3 carrots, cut into sticks"], instructions: ["Pat wings completely dry. Season with salt and garlic powder.", "Bake at 220°C for 40 minutes, flipping halfway, until skin is crispy.", "Melt butter and mix with hot sauce.", "Toss crispy wings in the buffalo sauce until coated.", "Make blue cheese dip: mash blue cheese with sour cream, mayo, and lemon juice.", "Serve wings with blue cheese dip, celery, and carrot sticks."] },
  { title: "Pancakes with Maple Syrup", description: "Fluffy buttermilk pancakes stacked high with butter and pure maple syrup.", cuisine: "American", diet: ["Vegetarian"], cookTimeMinutes: 20, servings: 4, ingredients: ["250g all-purpose flour", "350ml buttermilk", "2 eggs", "30g butter, melted, plus extra for cooking", "2 tsp baking powder", "2 tbsp sugar", "Pure maple syrup to serve"], instructions: ["Whisk flour, baking powder, sugar, and a pinch of salt together.", "In a separate bowl, whisk buttermilk, eggs, and melted butter.", "Pour wet ingredients into dry and stir until just combined (lumps are fine).", "Heat a griddle or pan over medium heat. Add a knob of butter.", "Pour 1/4 cup batter per pancake. Cook until bubbles form on surface, then flip.", "Cook 1 more minute until golden. Stack and serve with butter and maple syrup."] },

  // === CHINESE ===
  { title: "Dumplings (Jiaozi)", description: "Pan-fried pork and cabbage dumplings with a crispy bottom and savory dipping sauce.", cuisine: "Chinese", diet: ["Dairy-Free"], cookTimeMinutes: 45, servings: 4, ingredients: ["300g ground pork", "200g napa cabbage, finely minced and squeezed dry", "2 tbsp fresh ginger, grated", "3 garlic cloves, minced", "3 tbsp soy sauce", "1 tbsp sesame oil", "40 dumpling wrappers", "2 tbsp rice vinegar for dipping"], instructions: ["Mix pork, cabbage, ginger, garlic, soy sauce, and sesame oil thoroughly.", "Place a tablespoon of filling in the center of each wrapper.", "Moisten edges with water and fold into half-moon shapes, pleating one side.", "Heat oil in a non-stick pan. Place dumplings flat-side down.", "Fry for 2 minutes until bottoms are golden.", "Add 80ml water and cover immediately. Steam for 6 minutes until water evaporates.", "Serve with a dipping sauce of soy sauce, rice vinegar, and chili oil."] },
  { title: "Kung Pao Chicken", description: "Stir-fried chicken with peanuts, dried chilies, and Sichuan peppercorns in a savory-sweet sauce.", cuisine: "Chinese", diet: ["Dairy-Free"], cookTimeMinutes: 25, servings: 4, ingredients: ["500g chicken breast, diced", "80g roasted peanuts", "8 dried red chilies", "1 tsp Sichuan peppercorns", "3 tbsp soy sauce", "2 tbsp rice vinegar", "1 tbsp sugar", "4 garlic cloves, sliced"], instructions: ["Marinate chicken in 1 tbsp soy sauce and cornstarch for 15 minutes.", "Mix remaining soy sauce, rice vinegar, sugar, and cornstarch for the sauce.", "Heat oil in a wok until smoking. Stir-fry chicken until golden. Remove.", "Fry dried chilies and Sichuan peppercorns for 30 seconds until fragrant.", "Return chicken, add garlic, and pour in sauce.", "Toss in peanuts and stir-fry 1 minute until sauce thickens and coats everything.", "Serve immediately over steamed rice."] },
  { title: "Mapo Tofu", description: "Silken tofu in a fiery Sichuan sauce with ground pork, doubanjiang, and numbing peppercorns.", cuisine: "Chinese", diet: ["Dairy-Free"], cookTimeMinutes: 20, servings: 4, ingredients: ["400g silken tofu, cubed", "150g ground pork", "2 tbsp doubanjiang (fermented chili bean paste)", "1 tsp Sichuan peppercorns, ground", "3 garlic cloves, minced", "1 tbsp fresh ginger, minced", "3 green onions, sliced", "1 tbsp soy sauce"], instructions: ["Gently simmer tofu cubes in salted water for 2 minutes to firm up. Drain carefully.", "Brown ground pork in a wok over high heat, breaking into small pieces.", "Push pork aside. Fry doubanjiang in the oil for 1 minute until fragrant and red.", "Add garlic and ginger. Stir 30 seconds.", "Add 200ml broth, soy sauce, and tofu. Simmer gently for 5 minutes.", "Thicken with cornstarch slurry. Sprinkle with ground Sichuan pepper and green onions."] },
  { title: "Char Siu (BBQ Pork)", description: "Cantonese-style roasted pork with a sweet and sticky honey-hoisin glaze.", cuisine: "Chinese", diet: ["Dairy-Free"], cookTimeMinutes: 60, servings: 4, ingredients: ["600g pork shoulder, cut into long strips", "3 tbsp hoisin sauce", "3 tbsp honey", "2 tbsp soy sauce", "1 tsp five-spice powder", "3 garlic cloves, minced", "1 tbsp red fermented tofu (or red food coloring)"], instructions: ["Mix hoisin, honey, soy sauce, five-spice, garlic, and red fermented tofu into a marinade.", "Coat pork strips thoroughly. Marinate for 4+ hours (overnight is best).", "Preheat oven to 200°C. Place pork on a wire rack over a foil-lined tray.", "Roast for 20 minutes. Flip and baste with reserved marinade.", "Roast another 15 minutes. Baste again with honey for a final glaze.", "Broil for 2-3 minutes until edges are slightly charred.", "Rest 5 minutes, then slice against the grain and serve."] },
  { title: "Hot and Sour Soup", description: "Tangy and spicy soup with tofu, mushrooms, bamboo shoots, and egg ribbons.", cuisine: "Chinese", diet: ["Dairy-Free"], cookTimeMinutes: 20, servings: 4, ingredients: ["200g firm tofu, julienned", "100g shiitake mushrooms, sliced", "100g bamboo shoots, julienned", "2 eggs, beaten", "3 tbsp rice vinegar", "1 tsp white pepper", "3 tbsp soy sauce", "2 tbsp cornstarch mixed with water"], instructions: ["Bring 1L chicken or vegetable broth to a boil.", "Add mushrooms and bamboo shoots. Simmer 5 minutes.", "Add tofu, soy sauce, rice vinegar, and white pepper.", "Stir in cornstarch slurry to thicken the soup.", "Slowly drizzle in beaten eggs while stirring gently to form ribbons.", "Adjust seasoning — should be equally sour and spicy.", "Serve hot, drizzled with sesame oil and chili oil."] },
  { title: "Scallion Pancakes", description: "Flaky, crispy pan-fried flatbread layered with chopped scallions and sesame oil.", cuisine: "Chinese", diet: ["Vegan", "Dairy-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["300g all-purpose flour", "200ml boiling water", "6 scallions, finely chopped", "2 tbsp sesame oil", "1/2 tsp salt", "3 tbsp vegetable oil for frying"], instructions: ["Mix flour and boiling water until a shaggy dough forms. Knead until smooth. Rest 30 minutes.", "Divide into 4 portions. Roll each into a thin rectangle.", "Brush with sesame oil, sprinkle with salt and scallions.", "Roll up tightly into a log, then coil into a spiral. Flatten and roll out again.", "Pan-fry in oil over medium heat for 3 minutes per side until golden and flaky.", "Cut into wedges and serve with soy-vinegar dipping sauce."] },
  { title: "Dan Dan Noodles", description: "Spicy Sichuan noodles with minced pork, chili oil, and preserved vegetables.", cuisine: "Chinese", diet: ["Dairy-Free"], cookTimeMinutes: 20, servings: 2, ingredients: ["200g fresh wheat noodles", "150g ground pork", "3 tbsp chili oil", "2 tbsp soy sauce", "2 tbsp Chinese sesame paste (or tahini)", "1 tsp Sichuan peppercorns, ground", "2 tbsp preserved mustard greens (ya cai)", "2 tbsp roasted peanuts, crushed"], instructions: ["Mix soy sauce, sesame paste, chili oil, vinegar, and sugar in bowls for the sauce base.", "Brown ground pork in a dry wok until crispy. Add preserved vegetables and cook 1 minute.", "Cook noodles according to package directions. Drain.", "Divide sauce base between bowls. Add a splash of noodle cooking water.", "Top with noodles and crispy pork mixture.", "Garnish with crushed peanuts, scallions, and extra chili oil. Toss before eating."] },

  // === SPANISH ===
  { title: "Paella Valenciana", description: "Saffron-infused Spanish rice with chicken, rabbit, green beans, and snails — the original Valencia recipe.", cuisine: "Spanish", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 60, servings: 6, ingredients: ["400g bomba rice", "1 pinch saffron threads", "400g chicken thighs, cut into pieces", "300g rabbit, cut into pieces", "200g green beans, trimmed", "3 ripe tomatoes, grated", "4 tbsp olive oil", "1 sprig fresh rosemary"], instructions: ["Heat olive oil in a wide paella pan. Brown chicken and rabbit pieces on all sides. Remove.", "Sauté green beans for 3 minutes. Add grated tomato and cook until darkened.", "Return meat. Add 1.5L water, saffron, rosemary, and salt. Boil for 20 minutes.", "Add rice, distributing evenly. Do not stir from this point.", "Cook on high for 7 minutes, then reduce to medium for 12 minutes.", "If liquid remains, increase heat briefly to create the socarrat (crispy bottom).", "Rest off heat for 5 minutes before serving directly from the pan."] },
  { title: "Gazpacho", description: "Chilled Spanish tomato soup blended with peppers, cucumber, and sherry vinegar — perfect for summer.", cuisine: "Spanish", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 15, servings: 4, ingredients: ["1kg ripe tomatoes, roughly chopped", "1 cucumber, peeled and chopped", "1 red bell pepper, chopped", "2 garlic cloves", "4 tbsp extra virgin olive oil", "2 tbsp sherry vinegar", "1 slice day-old bread, soaked", "1/2 small onion"], instructions: ["Combine all vegetables, soaked bread, garlic, and onion in a blender.", "Blend until completely smooth.", "With the blender running, drizzle in olive oil and sherry vinegar.", "Season with salt and pepper. Blend once more.", "Strain through a fine sieve for extra smoothness (optional).", "Chill for at least 2 hours before serving.", "Serve cold with diced vegetables and a drizzle of olive oil on top."] },
  { title: "Patatas Bravas", description: "Crispy fried potato cubes with spicy bravas sauce and garlic aioli.", cuisine: "Spanish", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["800g potatoes, peeled and cubed", "3 tbsp olive oil", "200ml tomato sauce", "1 tsp smoked paprika", "1/2 tsp cayenne pepper", "3 garlic cloves, minced", "4 tbsp mayonnaise", "1 tbsp lemon juice"], instructions: ["Parboil potato cubes in salted water for 8 minutes. Drain and dry thoroughly.", "Fry potatoes in hot olive oil (or deep fry at 180°C) until golden and crispy.", "Make bravas sauce: simmer tomato sauce with smoked paprika, cayenne, and garlic for 5 minutes.", "Make aioli: mix mayonnaise with minced garlic and lemon juice.", "Pile crispy potatoes on a plate.", "Drizzle generously with bravas sauce and aioli. Serve hot."] },
  { title: "Gambas al Ajillo", description: "Sizzling garlic shrimp cooked in olive oil with chili flakes and parsley.", cuisine: "Spanish", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 10, servings: 4, ingredients: ["400g large shrimp, peeled", "8 garlic cloves, thinly sliced", "100ml extra virgin olive oil", "1 tsp chili flakes", "2 tbsp fresh parsley, chopped", "3 tbsp dry white wine", "Crusty bread to serve"], instructions: ["Heat olive oil in a small cazuela or cast-iron pan until very hot.", "Add sliced garlic and chili flakes. Sizzle for 30 seconds (don't burn the garlic).", "Add shrimp in a single layer. Cook 1 minute per side.", "Splash in white wine and let it bubble for 30 seconds.", "Remove from heat. Sprinkle with parsley.", "Serve immediately in the pan with crusty bread for dipping in the oil."] },
  { title: "Tortilla Española", description: "Classic Spanish potato and onion omelette, served warm or at room temperature.", cuisine: "Spanish", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 35, servings: 4, ingredients: ["5 medium potatoes, peeled and thinly sliced", "6 eggs", "1 large onion, thinly sliced", "200ml olive oil", "Salt to taste"], instructions: ["Gently fry potato and onion slices in olive oil over medium-low heat for 20 minutes until soft (not crispy).", "Drain potatoes and onion, reserving oil. Let cool slightly.", "Beat eggs with salt. Fold in the potato-onion mixture.", "Heat 2 tbsp reserved oil in a non-stick pan. Pour in the egg mixture.", "Cook on medium-low for 5 minutes until bottom is set.", "Flip using a plate. Slide back into pan and cook 3 more minutes.", "Serve warm or at room temperature, cut into wedges."] },
  { title: "Churros con Chocolate", description: "Crispy fried dough sticks served with thick, rich Spanish hot chocolate for dipping.", cuisine: "Spanish", diet: ["Vegetarian"], cookTimeMinutes: 25, servings: 4, ingredients: ["150g all-purpose flour", "250ml water", "30g butter", "Pinch of salt", "3 tbsp sugar mixed with 1 tsp cinnamon", "150g dark chocolate, chopped", "200ml whole milk"], instructions: ["Bring water, butter, and salt to a boil. Add flour all at once and stir until dough forms a ball.", "Transfer to a piping bag with a large star tip.", "Heat oil to 180°C. Pipe 12cm lengths into the oil.", "Fry for 3-4 minutes, turning once, until golden brown.", "Roll hot churros in cinnamon sugar.", "Make chocolate: heat milk and melt chocolate into it, whisking until thick.", "Serve churros hot with thick chocolate for dipping."] },

  // === VIETNAMESE ===
  { title: "Pho Bo", description: "Vietnamese beef noodle soup with a fragrant star anise and cinnamon broth, served with fresh herbs.", cuisine: "Vietnamese", diet: ["Dairy-Free"], cookTimeMinutes: 120, servings: 4, ingredients: ["1kg beef bones", "400g flat rice noodles", "3 star anise", "1 cinnamon stick", "1 large piece ginger, halved and charred", "200g bean sprouts", "Fresh Thai basil and cilantro", "3 tbsp fish sauce", "200g beef sirloin, thinly sliced"], instructions: ["Char ginger and onion over an open flame until blackened.", "Simmer beef bones in water for 2 hours, skimming impurities. Add star anise, cinnamon, and charred ginger.", "Season broth with fish sauce, sugar, and salt.", "Strain broth through a fine sieve.", "Cook rice noodles according to package. Divide into bowls.", "Top with raw sliced beef (the hot broth will cook it).", "Ladle boiling broth over the noodles and beef. Serve with bean sprouts, basil, lime, and hoisin sauce."] },
  { title: "Banh Mi", description: "Crusty baguette filled with pâté, pickled vegetables, cilantro, jalapeño, and grilled pork.", cuisine: "Vietnamese", diet: ["Dairy-Free"], cookTimeMinutes: 25, servings: 4, ingredients: ["4 small baguettes, split", "300g pork loin, thinly sliced", "4 tbsp pâté (chicken liver)", "2 carrots, julienned and pickled", "1 daikon radish, julienned and pickled", "Fresh cilantro sprigs", "2 jalapeños, sliced", "2 tbsp mayonnaise"], instructions: ["Marinate pork in fish sauce, sugar, garlic, and lemongrass for 30 minutes.", "Grill or pan-fry pork over high heat until charred, about 2 minutes per side.", "Toast baguettes until crispy outside but soft inside.", "Spread pâté on one side and mayonnaise on the other.", "Layer grilled pork, pickled carrots and daikon, cilantro, and jalapeño slices.", "Press together and serve immediately."] },
  { title: "Goi Cuon (Spring Rolls)", description: "Fresh rice paper rolls filled with shrimp, vermicelli, herbs, and served with peanut sauce.", cuisine: "Vietnamese", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 20, servings: 4, ingredients: ["12 rice paper wrappers", "12 cooked shrimp, halved lengthwise", "100g rice vermicelli, cooked", "Butter lettuce leaves", "Fresh mint leaves", "Fresh cilantro sprigs", "3 tbsp peanut butter", "2 tbsp hoisin sauce"], instructions: ["Prepare all fillings and arrange on a work surface.", "Dip one rice paper in warm water for 5 seconds until pliable.", "Lay on a damp surface. Place lettuce, vermicelli, herbs, and shrimp in the center.", "Fold bottom edge up over filling, fold in sides, then roll tightly.", "Repeat with remaining wrappers.", "Make peanut sauce: whisk peanut butter, hoisin, warm water, and chili until smooth.", "Serve rolls with peanut dipping sauce."] },
  { title: "Bun Cha", description: "Grilled pork patties and belly served with rice noodles, herbs, and sweet fish sauce dip.", cuisine: "Vietnamese", diet: ["Dairy-Free", "Gluten-Free"], cookTimeMinutes: 35, servings: 4, ingredients: ["250g ground pork, formed into small patties", "250g pork belly, thinly sliced", "300g rice vermicelli noodles", "4 tbsp fish sauce", "3 tbsp sugar", "3 garlic cloves, minced", "Butter lettuce and fresh herbs", "Pickled carrots and daikon"], instructions: ["Mix fish sauce, sugar, garlic, lime juice, and water for the dipping sauce.", "Season ground pork with fish sauce and pepper. Form into small patties.", "Grill pork patties and belly slices over charcoal or high heat until charred.", "Cook rice vermicelli and drain.", "Arrange noodles, lettuce, and herbs on plates.", "Place grilled pork in bowls of dipping sauce.", "Eat by dipping noodles and herbs into the sauce with the pork."] },
  { title: "Ca Kho To (Caramelized Fish)", description: "Catfish braised in a clay pot with caramel sauce, fish sauce, and black pepper.", cuisine: "Vietnamese", diet: ["Dairy-Free", "Gluten-Free"], cookTimeMinutes: 30, servings: 4, ingredients: ["500g catfish steaks", "3 tbsp sugar (for caramel)", "3 tbsp fish sauce", "1 tsp freshly ground black pepper", "3 shallots, sliced", "3 garlic cloves, minced", "100ml coconut water"], instructions: ["Make caramel: heat sugar in a dry clay pot until amber colored.", "Carefully add fish sauce and coconut water to the caramel (it will splutter).", "Add shallots and garlic. Stir until dissolved.", "Place catfish steaks in the sauce in a single layer.", "Simmer on low heat for 20 minutes, basting fish occasionally.", "The sauce should reduce to a thick, dark glaze. Season with black pepper.", "Serve over steamed rice with the caramel sauce spooned on top."] },

  // === GREEK ===
  { title: "Greek Moussaka", description: "Layered eggplant and spiced lamb casserole topped with creamy béchamel sauce.", cuisine: "Greek", diet: [], cookTimeMinutes: 90, servings: 6, ingredients: ["3 large eggplants, sliced 1cm thick", "500g ground lamb", "400g canned tomatoes", "1 onion, diced", "1 tsp cinnamon", "500ml béchamel sauce", "60g Parmesan, grated", "Pinch of nutmeg"], instructions: ["Salt eggplant slices and let drain 30 minutes. Pat dry and brush with olive oil.", "Grill or bake eggplant slices until golden on both sides.", "Brown lamb with onion. Add tomatoes, cinnamon, salt, and pepper. Simmer 15 minutes.", "Make béchamel: melt butter, whisk in flour, gradually add milk. Season with nutmeg.", "Layer eggplant, meat sauce, eggplant, meat sauce in a baking dish.", "Pour béchamel over the top. Sprinkle with Parmesan.", "Bake at 180°C for 40 minutes until golden and bubbly. Rest 15 minutes before cutting."] },
  { title: "Souvlaki", description: "Grilled marinated pork skewers served in pita with tzatziki, tomatoes, and onions.", cuisine: "Greek", diet: [], cookTimeMinutes: 25, servings: 4, ingredients: ["600g pork shoulder, cubed", "4 tbsp olive oil", "2 tbsp lemon juice", "2 tsp dried oregano", "4 pita breads", "200g tzatziki", "2 tomatoes, sliced", "1 red onion, thinly sliced"], instructions: ["Marinate pork cubes in olive oil, lemon juice, oregano, garlic, salt, and pepper for 2+ hours.", "Thread pork onto metal skewers.", "Grill over high heat for 3-4 minutes per side until charred and cooked through.", "Warm pita breads on the grill for 30 seconds per side.", "Slide meat off skewers onto pita.", "Top with tzatziki, tomato slices, and red onion.", "Wrap and serve with lemon wedges."] },
  { title: "Spanakopita", description: "Flaky phyllo pastry filled with spinach, feta cheese, and fresh herbs.", cuisine: "Greek", diet: ["Vegetarian"], cookTimeMinutes: 45, servings: 8, ingredients: ["12 sheets phyllo dough", "500g fresh spinach, wilted and squeezed dry", "200g feta cheese, crumbled", "1 onion, finely diced", "3 tbsp fresh dill, chopped", "3 eggs, beaten", "4 tbsp olive oil", "60g butter, melted"], instructions: ["Sauté onion until soft. Add spinach and cook until moisture evaporates.", "Cool slightly, then mix with feta, dill, and beaten eggs. Season with pepper.", "Brush a baking dish with butter. Layer 6 sheets of phyllo, brushing each with melted butter.", "Spread spinach-feta filling evenly over the phyllo.", "Layer remaining 6 sheets on top, brushing each with butter.", "Score the top layers into squares or diamonds.", "Bake at 180°C for 35-40 minutes until golden and crispy."] },
  { title: "Greek Salad", description: "Chunky tomatoes, cucumber, red onion, olives, and feta with oregano and olive oil.", cuisine: "Greek", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 10, servings: 4, ingredients: ["4 ripe tomatoes, cut into chunks", "1 cucumber, thickly sliced", "1 red onion, thinly sliced", "100g kalamata olives", "150g feta cheese, in one block", "1 tsp dried oregano", "4 tbsp extra virgin olive oil"], instructions: ["Cut tomatoes into large chunks. Slice cucumber into thick half-moons.", "Arrange tomatoes, cucumber, and red onion on a plate.", "Scatter olives over the vegetables.", "Place the block of feta on top (don't crumble it — that's the traditional way).", "Sprinkle with dried oregano.", "Drizzle generously with olive oil and season with salt. Serve immediately."] },
  { title: "Tzatziki", description: "Cool and creamy yogurt dip with cucumber, garlic, dill, and lemon.", cuisine: "Greek", diet: ["Vegetarian", "Gluten-Free"], cookTimeMinutes: 10, servings: 4, ingredients: ["400g thick Greek yogurt", "1 cucumber, grated and squeezed dry", "2 garlic cloves, finely grated", "2 tbsp fresh dill, chopped", "1 tbsp lemon juice", "2 tbsp extra virgin olive oil", "Salt to taste"], instructions: ["Grate cucumber and squeeze out as much liquid as possible using a clean towel.", "Combine yogurt, cucumber, garlic, dill, and lemon juice.", "Season with salt and stir well.", "Transfer to a serving bowl and drizzle with olive oil.", "Refrigerate for 30 minutes before serving to let flavors meld."] },

  // === MOROCCAN ===
  { title: "Lamb Tagine", description: "Slow-cooked Moroccan lamb with apricots, almonds, and warm spices in a conical clay pot.", cuisine: "Moroccan", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 150, servings: 6, ingredients: ["1kg lamb shoulder, cubed", "100g dried apricots", "60g blanched almonds, toasted", "2 tsp cinnamon", "2 tsp cumin", "2 tbsp honey", "2 onions, diced", "1 pinch saffron threads"], instructions: ["Season lamb with cinnamon, cumin, salt, and pepper.", "Brown lamb in batches in olive oil. Remove and set aside.", "Sauté onions until golden. Add saffron and a splash of water.", "Return lamb to the pot. Add enough water to just cover.", "Cover and simmer on low heat for 1.5 hours until lamb is tender.", "Add apricots and honey. Cook 20 more minutes.", "Serve topped with toasted almonds and fresh cilantro over couscous."] },
  { title: "Couscous Royale", description: "Fluffy semolina couscous with seven vegetables, lamb, and merguez sausage.", cuisine: "Moroccan", diet: ["Dairy-Free"], cookTimeMinutes: 90, servings: 6, ingredients: ["500g couscous", "400g lamb shoulder, cubed", "4 merguez sausages", "2 zucchini, chunked", "3 carrots, chunked", "2 turnips, chunked", "1 can chickpeas, drained", "2 tbsp harissa paste"], instructions: ["Brown lamb in a large pot. Add onion and cook 5 minutes.", "Add carrots, turnips, and enough water to cover. Simmer 45 minutes.", "Add zucchini and chickpeas. Cook 15 more minutes.", "Grill merguez sausages until charred.", "Steam couscous: pour boiling broth over couscous, cover, and fluff with a fork after 5 minutes.", "Mound couscous on a large platter. Arrange meat and vegetables on top.", "Serve with broth on the side and harissa for heat."] },
  { title: "Harira", description: "Hearty Moroccan soup with lentils, chickpeas, tomatoes, and warming spices — traditional Ramadan fare.", cuisine: "Moroccan", diet: ["Vegan", "Dairy-Free"], cookTimeMinutes: 45, servings: 6, ingredients: ["200g brown lentils", "1 can chickpeas, drained", "400g canned tomatoes", "1 onion, diced", "2 celery stalks, diced", "1 tbsp fresh ginger, grated", "1 tsp cinnamon", "1/2 cup fresh cilantro, chopped"], instructions: ["Sauté onion and celery in olive oil for 5 minutes.", "Add ginger, cinnamon, turmeric, and pepper. Cook 1 minute.", "Add tomatoes, lentils, and 1.5L water. Bring to a boil.", "Simmer for 30 minutes until lentils are tender.", "Add chickpeas and cook 10 more minutes.", "Stir in fresh cilantro and lemon juice.", "Serve hot with crusty bread and lemon wedges."] },

  // === PERUVIAN ===
  { title: "Ceviche", description: "Fresh raw fish cured in citrus juices with red onion, cilantro, and chili peppers.", cuisine: "Peruvian", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 20, servings: 4, ingredients: ["500g firm white fish (sea bass or corvina), cubed", "150ml fresh lime juice", "1 red onion, thinly sliced", "1/4 cup fresh cilantro, chopped", "1 aji amarillo or habanero, minced", "1 sweet potato, boiled and sliced", "2 ears corn, boiled"], instructions: ["Cut fish into 2cm cubes. Place in a glass bowl.", "Pour lime juice over fish, ensuring all pieces are submerged.", "Add sliced red onion, chili, and salt. Toss gently.", "Refrigerate for 15 minutes (no longer or fish becomes tough).", "Stir in cilantro.", "Serve immediately on a plate with boiled sweet potato and corn on the side.", "Spoon the leche de tigre (citrus marinade) over the top."] },
  { title: "Lomo Saltado", description: "Peruvian stir-fry of beef, tomatoes, and onions with soy sauce, served over fries and rice.", cuisine: "Peruvian", diet: ["Dairy-Free"], cookTimeMinutes: 25, servings: 4, ingredients: ["500g beef sirloin, cut into thick strips", "3 tomatoes, cut into wedges", "1 red onion, cut into thick slices", "3 tbsp soy sauce", "2 tbsp red wine vinegar", "300g french fries (freshly fried)", "2 cups cooked white rice", "Fresh cilantro to garnish"], instructions: ["Heat a wok or large pan until smoking hot.", "Sear beef strips in batches for 1 minute — keep them rare inside. Remove.", "In the same pan, stir-fry onion wedges for 1 minute.", "Add tomato wedges and cook 30 seconds.", "Return beef. Add soy sauce and vinegar. Toss for 30 seconds.", "Toss in hot french fries and cilantro.", "Serve immediately alongside steamed white rice."] },
  { title: "Aji de Gallina", description: "Shredded chicken in a creamy walnut and yellow pepper sauce over rice.", cuisine: "Peruvian", diet: ["Gluten-Free"], cookTimeMinutes: 45, servings: 4, ingredients: ["500g chicken breast, poached and shredded", "3 aji amarillo peppers (or 3 tbsp paste)", "60g walnuts", "2 slices white bread, crusts removed", "50g Parmesan, grated", "200ml evaporated milk", "1 onion, diced", "3 garlic cloves, minced"], instructions: ["Poach chicken breasts in salted water. Shred and reserve broth.", "Soak bread in evaporated milk.", "Blend aji amarillo, walnuts, and soaked bread until smooth.", "Sauté onion and garlic until soft. Add the blended sauce.", "Simmer for 10 minutes, adding chicken broth to reach a creamy consistency.", "Stir in shredded chicken and Parmesan. Cook 5 more minutes.", "Serve over rice, garnished with olives and hard-boiled egg slices."] },

  // === BRITISH ===
  { title: "Fish and Chips", description: "Beer-battered cod with thick-cut chips, mushy peas, and tartar sauce — the British pub classic.", cuisine: "British", diet: [], cookTimeMinutes: 35, servings: 4, ingredients: ["4 cod fillets (180g each)", "200g self-raising flour, plus extra for dusting", "250ml cold beer", "800g potatoes, cut into thick chips", "200g peas", "4 tbsp tartar sauce", "1 lemon, cut into wedges", "Malt vinegar to serve"], instructions: ["Soak chips in cold water for 30 minutes. Drain and dry thoroughly.", "Fry chips at 140°C for 8 minutes to blanch. Remove and increase oil to 180°C.", "Make batter: whisk flour, beer, and a pinch of salt until smooth.", "Dust cod fillets in flour, then dip in batter.", "Fry fish for 5-6 minutes until golden and crispy. Drain on paper towels.", "Fry chips again at 180°C for 3-4 minutes until golden and crispy.", "Serve with mushy peas, tartar sauce, lemon wedges, and malt vinegar."] },
  { title: "Banoffee Pie", description: "A no-bake British dessert with layers of toffee, bananas, and whipped cream on a biscuit base.", cuisine: "British", diet: ["Vegetarian"], cookTimeMinutes: 30, servings: 8, ingredients: ["250g digestive biscuits, crushed", "100g butter, melted", "1 can (397g) condensed milk, boiled for 3 hours (or dulce de leche)", "3 ripe bananas, sliced", "300ml whipping cream, whipped", "30g dark chocolate, grated"], instructions: ["Mix crushed biscuits with melted butter. Press firmly into the base of a 23cm springform tin.", "Refrigerate for 15 minutes until set.", "Spread the caramelized condensed milk (toffee) evenly over the biscuit base.", "Arrange sliced bananas over the toffee layer.", "Spread whipped cream generously over the bananas.", "Grate dark chocolate over the top.", "Refrigerate for 1 hour before serving."] },
  { title: "Shepherd's Pie", description: "Savory lamb mince with vegetables topped with creamy mashed potatoes and baked golden.", cuisine: "British", diet: ["Gluten-Free"], cookTimeMinutes: 60, servings: 6, ingredients: ["500g lamb mince", "1kg potatoes, peeled and cubed", "2 carrots, diced", "1 cup peas", "1 onion, diced", "2 tbsp tomato paste", "2 tbsp Worcestershire sauce", "50g butter"], instructions: ["Boil potatoes until tender. Mash with butter, milk, salt, and pepper.", "Brown lamb mince in a large pan, breaking up lumps.", "Add onion and carrots. Cook 5 minutes.", "Stir in tomato paste, Worcestershire sauce, and 200ml stock. Simmer 15 minutes.", "Add peas and transfer filling to a baking dish.", "Spread mashed potato over the top, roughing up the surface with a fork.", "Bake at 200°C for 25 minutes until potato is golden and filling bubbles at edges."] },
  { title: "Full English Breakfast", description: "The classic fry-up with bacon, eggs, sausages, beans, toast, tomatoes, and mushrooms.", cuisine: "British", diet: [], cookTimeMinutes: 20, servings: 2, ingredients: ["4 rashers back bacon", "4 eggs", "4 pork sausages", "1 can baked beans", "4 slices thick white bread", "2 tomatoes, halved", "150g mushrooms, sliced", "Butter for toast and frying"], instructions: ["Start sausages in a cold pan. Cook over medium heat for 12 minutes, turning regularly.", "Add bacon to the pan and cook 3 minutes per side.", "Fry mushrooms and tomato halves in butter until softened.", "Heat baked beans in a small saucepan.", "Fry eggs in butter to your preference (sunny-side up or over-easy).", "Toast bread and butter generously.", "Arrange everything on warm plates and serve immediately."] },
  { title: "Sticky Toffee Pudding", description: "Moist date sponge cake drenched in warm toffee sauce, served with vanilla custard.", cuisine: "British", diet: ["Vegetarian"], cookTimeMinutes: 45, servings: 6, ingredients: ["200g pitted dates, chopped", "175g self-raising flour", "75g butter, softened", "150g dark brown sugar", "2 eggs", "150ml double cream (for sauce)", "1 tsp vanilla extract", "1 tsp baking soda"], instructions: ["Soak dates in 200ml boiling water with baking soda for 10 minutes.", "Cream butter and half the sugar. Beat in eggs and vanilla.", "Fold in flour, then stir in dates and their liquid.", "Pour into a greased baking dish. Bake at 180°C for 30 minutes.", "Make toffee sauce: melt remaining sugar with butter and cream. Simmer 3 minutes.", "Poke holes in the warm cake and pour half the sauce over.", "Serve warm with remaining sauce and custard or cream."] },

  // === CARIBBEAN ===
  { title: "Jerk Chicken", description: "Spicy Jamaican grilled chicken marinated in scotch bonnet peppers, allspice, and thyme.", cuisine: "Caribbean", diet: ["Gluten-Free", "Dairy-Free"], cookTimeMinutes: 60, servings: 4, ingredients: ["1.5kg chicken pieces (legs and thighs)", "3 scotch bonnet peppers, seeded", "2 tbsp ground allspice", "6 sprigs fresh thyme", "6 garlic cloves", "2 tbsp fresh ginger, grated", "3 tbsp soy sauce", "2 limes, juiced"], instructions: ["Blend scotch bonnets, allspice, thyme, garlic, ginger, soy sauce, and lime juice into a paste.", "Score chicken pieces deeply. Rub marinade all over and into the cuts.", "Marinate for 4+ hours (overnight is best).", "Grill chicken over medium-high heat for 30-35 minutes, turning regularly.", "Baste with extra marinade during the last 10 minutes.", "Chicken is done when juices run clear and skin is charred.", "Serve with rice and peas and festival (fried dumplings)."] },
  { title: "Rice and Peas", description: "Coconut-infused rice cooked with kidney beans, thyme, and scotch bonnet — a Jamaican staple.", cuisine: "Caribbean", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 35, servings: 6, ingredients: ["2 cups long-grain rice", "1 can kidney beans, with liquid", "400ml coconut milk", "3 sprigs fresh thyme", "1 whole scotch bonnet pepper (uncut)", "3 garlic cloves, minced", "4 scallions, chopped"], instructions: ["Bring coconut milk, kidney beans (with liquid), and 1 cup water to a boil.", "Add thyme, whole scotch bonnet (don't pierce it), garlic, and scallions.", "Add rice and stir once. Reduce heat to lowest setting.", "Cover tightly and cook for 20 minutes without lifting the lid.", "Remove from heat and let steam for 5 minutes.", "Remove scotch bonnet and thyme sprigs. Fluff with a fork and serve."] },
  { title: "Plantain Fritters", description: "Sweet ripe plantains fried until golden and caramelized — a simple Caribbean treat.", cuisine: "Caribbean", diet: ["Vegan", "Gluten-Free", "Dairy-Free"], cookTimeMinutes: 15, servings: 4, ingredients: ["3 very ripe plantains (black skin)", "3 tbsp coconut oil or vegetable oil", "Pinch of salt", "Pinch of cinnamon"], instructions: ["Peel plantains and slice diagonally into 1cm thick pieces.", "Heat oil in a large pan over medium heat.", "Fry plantain slices for 2-3 minutes per side until deep golden and caramelized.", "Drain on paper towels.", "Sprinkle with a pinch of salt and cinnamon while still hot.", "Serve as a side dish or snack."] },

  // === ETHIOPIAN ===
  { title: "Doro Wat", description: "Spicy Ethiopian chicken stew with berbere spice, hard-boiled eggs, and injera bread.", cuisine: "Ethiopian", diet: ["Dairy-Free"], cookTimeMinutes: 90, servings: 4, ingredients: ["8 chicken drumsticks, scored", "3 tbsp berbere spice blend", "4 onions, finely diced", "4 garlic cloves, minced", "2 tbsp fresh ginger, grated", "4 hard-boiled eggs", "3 tbsp niter kibbeh (spiced butter) or oil", "Injera bread to serve"], instructions: ["Dry-cook diced onions in a pot (no oil) for 15 minutes, stirring constantly, until deeply browned.", "Add niter kibbeh, garlic, and ginger. Cook 3 minutes.", "Add berbere spice and cook 2 minutes, stirring to prevent burning.", "Add 250ml water and bring to a simmer.", "Add chicken pieces, cover, and cook for 45 minutes until tender.", "Score hard-boiled eggs and nestle into the stew for the last 10 minutes.", "Serve on a large platter of injera bread."] },
  { title: "Misir Wat", description: "Spiced red lentil stew with berbere and served on spongy injera flatbread.", cuisine: "Ethiopian", diet: ["Vegan", "Dairy-Free"], cookTimeMinutes: 40, servings: 4, ingredients: ["300g red lentils, rinsed", "3 tbsp berbere spice blend", "3 onions, finely diced", "4 garlic cloves, minced", "2 tbsp tomato paste", "3 tbsp vegetable oil", "Salt to taste", "Injera bread to serve"], instructions: ["Dry-cook diced onions for 12 minutes until deeply caramelized (no oil needed).", "Add oil, garlic, and berbere spice. Cook 2 minutes until fragrant.", "Stir in tomato paste and cook 1 minute.", "Add lentils and 600ml water. Bring to a boil.", "Reduce heat and simmer for 25 minutes, stirring occasionally, until lentils are soft and stew is thick.", "Season with salt. Serve on injera bread."] },

  // === TURKISH ===
  { title: "Lahmacun", description: "Thin crispy Turkish flatbread topped with spiced minced meat, herbs, and lemon.", cuisine: "Turkish", diet: ["Dairy-Free"], cookTimeMinutes: 20, servings: 4, ingredients: ["4 thin flatbread rounds (or pizza dough rolled very thin)", "300g ground lamb", "2 tomatoes, finely diced", "1 onion, finely diced", "1/4 cup fresh parsley, chopped", "1 tsp red pepper flakes", "1 lemon, cut into wedges", "1 tsp sumac"], instructions: ["Mix ground lamb with diced tomatoes, onion, parsley, red pepper flakes, and salt.", "Roll dough into very thin rounds (paper-thin is ideal).", "Spread a thin layer of meat mixture over each round, edge to edge.", "Bake at 250°C on a preheated baking sheet for 5-6 minutes until edges are crispy.", "Squeeze lemon juice over the top and sprinkle with sumac.", "Roll up with fresh herbs and eat by hand."] },
  { title: "Iskender Kebab", description: "Sliced döner meat over pita bread with tomato sauce, yogurt, and browned butter.", cuisine: "Turkish", diet: [], cookTimeMinutes: 30, servings: 4, ingredients: ["500g lamb döner meat (or thinly sliced lamb leg)", "4 pita breads, cubed", "300ml tomato sauce, seasoned with paprika", "300g thick yogurt", "60g butter", "2 green peppers, grilled"], instructions: ["Slice lamb very thinly and cook in a hot pan until browned and slightly crispy.", "Warm tomato sauce with a pinch of paprika and sugar.", "Arrange cubed pita bread on serving plates.", "Drizzle tomato sauce over the bread.", "Pile sliced meat on top.", "Add a generous dollop of yogurt on the side.", "Brown butter in a small pan until foaming and nutty. Drizzle over everything. Serve with grilled peppers."] },
  { title: "Baklava", description: "Layers of crispy phyllo pastry filled with chopped nuts and soaked in honey syrup.", cuisine: "Turkish", diet: ["Vegetarian"], cookTimeMinutes: 60, servings: 12, ingredients: ["500g phyllo dough", "200g pistachios, finely chopped", "100g walnuts, finely chopped", "200g butter, melted", "200g sugar", "3 tbsp honey", "1 tbsp lemon juice", "1 tsp cinnamon"], instructions: ["Make syrup: boil sugar with 200ml water, honey, and lemon juice. Simmer 10 minutes. Cool completely.", "Brush a baking dish with butter. Layer 8 sheets of phyllo, brushing each with melted butter.", "Spread a thin layer of mixed nuts. Add 4 more buttered phyllo sheets.", "Repeat nut and phyllo layers until nuts are used up. Finish with 8 buttered sheets on top.", "Cut into diamond shapes with a sharp knife before baking.", "Bake at 170°C for 45 minutes until deep golden.", "Pour cold syrup over hot baklava immediately. Let soak for 4+ hours before serving."] },
];
